async function resolveTargetNode() {
  if (!expected.targetNodeId) return figma.currentPage;
  const node = typeof figma.getNodeByIdAsync === "function"
    ? await figma.getNodeByIdAsync(expected.targetNodeId)
    : figma.getNodeById(expected.targetNodeId);
  if (!node) throw new Error("Figma target node not found: " + expected.targetNodeId);
  if (!("children" in node)) throw new Error("Figma target node has no children: " + node.type);
  return node;
}

async function prepareTargetPage(targetNode) {
  const page = targetNode.type === "PAGE" ? targetNode : findAncestorPage(targetNode);
  if (page && figma.currentPage.id !== page.id) await figma.setCurrentPageAsync(page);
}

function findAncestorPage(node) {
  let current = node;
  while (current) {
    if (current.type === "PAGE") return current;
    current = current.parent;
  }
  return null;
}

function findNamed(root, name, type) {
  if (!("findOne" in root)) return null;
  return root.findOne((node) => node.name === name && (!type || node.type === type));
}
